 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { useDispatch } from 'react-redux';
 4	import { Label, Tooltip } from '@patternfly/react-core';
 5	import { PencilAltIcon } from '@patternfly/react-icons';
 6	
 7	import { isAttachmentChanged } from '../attachments';
 8	import { openAttachmentSet } from '../redux-actions';
 9	import { Attachment } from '../types';
10	import ResourceIcon from './ResourceIcon';
11	
12	type AttachmentLabelProps = {
13	  attachment: Attachment;
14	  isEditable?: boolean;
15	  onClose?: () => void;
16	};
17	
18	const AttachmentLabel: React.FC<AttachmentLabelProps> = ({ attachment, isEditable, onClose }) => {
19	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
20	
21	  const dispatch = useDispatch();
22	
23	  const onClick = React.useCallback(() => {
24	    dispatch(openAttachmentSet(Object.assign({}, attachment, { isEditable })));
25	  }, [attachment, isEditable, dispatch]);
26	
27	  if (!attachment) {
28	    return null;
29	  }
30	
31	  const { attachmentType, kind, name, value } = attachment;
32	  const isChanged = isAttachmentChanged(attachment);
33	
34	  return (
35	    <Tooltip
36	      content={
37	        <>
38	          {isChanged ? t('Preview attachment - modified') : t('Preview attachment')}{' '}
39	          {t('({{num}} characters)', { num: value?.length?.toLocaleString() ?? '0' })}
40	        </>
41	      }
42	    >
43	      <Label className="ols-plugin__context-label" onClick={onClick} onClose={onClose}>
44	        <ResourceIcon kind={kind} />
45	        <span className="ols-plugin__context-label-text">{name}</span>
46	        {isChanged && (
47	          <span className="ols-plugin__inline-icon">
48	            <PencilAltIcon />
49	          </span>
50	        )}
51	        {kind !== 'Alert' && <Label className="ols-plugin__inline-icon">{attachmentType}</Label>}
52	      </Label>
53	    </Tooltip>
54	  );
55	};
56	
57	export default AttachmentLabel;

